class Solution {
public:
    string answerString(string word, int numFriends) {
        string ans = word;
        for (int i = word.length() - 1; i >= numFriends; --i) {
            for (int j = 0; j <= i - numFriends; ++j) {
                string left = word.substr(0, j + 1);
                string right = word.substr(j + 1, i - j);
                if (left > ans) ans = left;
                if (right > ans) ans = right;
            }
        }
        return ans;
    }
};
